const Box = forwardHTMLRef<{ width: number }, 'div'>(({ width }, ref) => (
  <div
    ref={ref}
    style={{ width }}
    className={stylex(stylex.create({ padding: 4, boxSizing: 'border-box', height: '100%' }))}
  >
    <div
      className={stylex(
        stylex.create({
          backgroundColor: $token['primary-content-default'],
          height: '100%',
        }),
      )}
    />
  </div>
));

export const AllCases = () => {
  const count = 36;
  const [slideIndex, setSlideIndex] = React.useState(0);
  return (
    <div style={{ padding: 36 }}>
      <Divider>Dynamic width</Divider>
      <Carousel style={{ height: 320 }}>
        <CarouselSlide fullWidth={false}>
          <Box width={200} />
        </CarouselSlide>
        <CarouselSlide fullWidth={false}>
          <Box width={80} />
        </CarouselSlide>
      </Carousel>
      <Divider>Pressure test: 1000</Divider>
      <Carousel style={{ height: 320 }}>
        {Array(1000)
          .fill(0)
          .map((_, i) => `https://www.dmoe.cc/random.php?id=${i}`)
          .map((src, i) => (
            <CarouselSlide
              key={i}
              fullWidth={false}
              style={{
                minWidth: 200,
              }}
            >
              <img src={src} style={{ height: '100%' }} />
            </CarouselSlide>
          ))}
      </Carousel>
      <Divider>Different indicator type and theme, controlled mode</Divider>
      <div style={{ padding: '0 36px' }}>
        <Slider value={slideIndex} min={0} max={count} onChange={setSlideIndex} step={1} />
      </div>
      {(() => {
        const cases: CarouselProps[] = [
          { indicatorProps: { type: 'dot', theme: 'light' } },
          { indicatorProps: { type: 'line', theme: 'light' } },
          {
            indicatorProps: { type: 'dot', theme: 'primary' },
            indicatorPosition: 'outer-bottom',
          },
          {
            indicatorProps: { type: 'line', theme: 'primary' },
            indicatorPosition: 'outer-bottom',
          },
        ];
        return cases.map(props => (
          <React.Fragment key={JSON.stringify(props)}>
            <Divider />
            <Carousel style={{ height: 320 }} slideIndex={slideIndex} onSlideIndexChange={setSlideIndex} {...props}>
              {Array(count)
                .fill(0)
                .map((_, i) => urls[i % urls.length])
                .map((src, i) => (
                  <CarouselSlide
                    key={i}
                    fullWidth={false}
                    style={{
                      minWidth: 200,
                    }}
                  >
                    <img
                      src={src}
                      alt={src}
                      style={{
                        height: '100%',
                      }}
                    />
                  </CarouselSlide>
                ))}
            </Carousel>
            <Divider />
            <Carousel style={{ height: 320 }} slideIndex={slideIndex} onSlideIndexChange={setSlideIndex} {...props}>
              {Array(count)
                .fill(0)
                .map((_, i) => urls[i % urls.length])
                .map((src, i) => (
                  <CarouselSlide key={i}>
                    <img
                      src={src}
                      alt={src}
                      style={{
                        width: '100%',
                        height: '100%',
                        objectFit: 'cover',
                        objectPosition: 'center center',
                      }}
                    />
                  </CarouselSlide>
                ))}
            </Carousel>
          </React.Fragment>
        ));
      })()}
    </div>
  );
};
